import type * as monaco from 'monaco-editor';

export function defineForgeScriptLanguage(monaco: any) {
  // ForgeScript API type definitions
  const forgeScriptTypes = `
    declare module '@psyforge/forgescript' {
      export interface ExperimentConfig {
        name: string;
        description?: string;
        version?: string;
        author?: string;
        metadata?: Record<string, any>;
      }

      export interface Timeline {
        name?: string;
        duration?: number;
        trials: Trial[];
      }

      export interface Trial {
        name?: string;
        duration?: number;
        stimuli: Stimulus[];
        responses?: Response[];
      }

      export interface Stimulus {
        type: 'text' | 'image' | 'audio' | 'video' | 'shape';
        content: any;
        duration: number;
        position?: { x: number; y: number };
        style?: Record<string, any>;
      }

      export interface Response {
        type: 'keyboard' | 'mouse' | 'touch';
        validKeys?: string[];
        timeout?: number;
      }

      export interface ExperimentBuilder {
        name(name: string): ExperimentBuilder;
        description(desc: string): ExperimentBuilder;
        author(author: string): ExperimentBuilder;
        metadata(data: Record<string, any>): ExperimentBuilder;
        timeline(name: string): TimelineBuilder;
        build(): CompiledExperiment;
      }

      export interface TimelineBuilder {
        trial(name: string): TrialBuilder;
        duration(ms: number): TimelineBuilder;
        loop(count: number): TimelineBuilder;
        randomize(): TimelineBuilder;
        build(): Timeline;
      }

      export interface TrialBuilder {
        stimulus(stim: Stimulus): TrialBuilder;
        text(content: string, duration: number): TrialBuilder;
        image(url: string, duration: number): TrialBuilder;
        audio(url: string): TrialBuilder;
        video(url: string): TrialBuilder;
        response(type: string, options?: any): TrialBuilder;
        duration(ms: number): TrialBuilder;
        build(): Trial;
      }

      export interface CompiledExperiment {
        id: string;
        name: string;
        description?: string;
        timelines: Timeline[];
        duration?: number;
      }

      export function experiment(config?: ExperimentConfig): ExperimentBuilder;
      export function timeline(name?: string): TimelineBuilder;
      export function trial(name?: string): TrialBuilder;

      // Stimulus factory functions
      export function textStimulus(content: string, duration: number): Stimulus;
      export function imageStimulus(url: string, duration: number): Stimulus;
      export function audioStimulus(url: string): Stimulus;
      export function videoStimulus(url: string): Stimulus;
      export function shapeStimulus(type: string, duration: number): Stimulus;

      // Response factory functions
      export function keyboardResponse(validKeys?: string[], timeout?: number): Response;
      export function mouseResponse(validButtons?: string[], timeout?: number): Response;
      export function touchResponse(timeout?: number): Response;

      // Utility functions
      export function sequence(...trials: Trial[]): Trial[];
      export function randomize(...trials: Trial[]): Trial[];
      export function repeat(trial: Trial, count: number): Trial[];
      export function factorial(factors: Record<string, any[]>): Trial[];
    }
  `;

  // Add ForgeScript types to Monaco
  monaco.languages.typescript.typescriptDefaults.addExtraLib(
    forgeScriptTypes,
    'file:///node_modules/@types/psyforge-forgescript/index.d.ts'
  );

  // Add IntelliSense snippets
  monaco.languages.registerCompletionItemProvider('typescript', {
    provideCompletionItems: (model: any, position: any) => {
      const suggestions = [
        {
          label: 'experiment',
          kind: monaco.languages.CompletionItemKind.Function,
          insertText: `experiment()
  .name('\${1:Experiment Name}')
  .description('\${2:Description}')
  .timeline('\${3:main}')
    .trial('\${4:trial1}')
      .text('\${5:Hello World}', \${6:1000})
      .response('keyboard')
    .build()
  .build()`,
          insertTextRules: monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet,
          documentation: 'Create a new ForgeScript experiment'
        },
        {
          label: 'trial',
          kind: monaco.languages.CompletionItemKind.Function,
          insertText: `trial('\${1:trialName}')
  .text('\${2:stimulus text}', \${3:1000})
  .response('keyboard', { validKeys: ['\${4:space}'] })
  .build()`,
          insertTextRules: monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet,
          documentation: 'Create a new trial'
        },
        {
          label: 'textStimulus',
          kind: monaco.languages.CompletionItemKind.Function,
          insertText: `textStimulus('\${1:text}', \${2:1000})`,
          insertTextRules: monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet,
          documentation: 'Create a text stimulus'
        },
        {
          label: 'imageStimulus',
          kind: monaco.languages.CompletionItemKind.Function,
          insertText: `imageStimulus('\${1:path/to/image.png}', \${2:1000})`,
          insertTextRules: monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet,
          documentation: 'Create an image stimulus'
        },
        {
          label: 'keyboardResponse',
          kind: monaco.languages.CompletionItemKind.Function,
          insertText: `keyboardResponse(['\${1:space}', '\${2:enter}'], \${3:5000})`,
          insertTextRules: monaco.languages.CompletionItemInsertTextRule.InsertAsSnippet,
          documentation: 'Create a keyboard response collector'
        }
      ];

      return { suggestions };
    }
  });

  // Register hover provider for ForgeScript API
  monaco.languages.registerHoverProvider('typescript', {
    provideHover: (model: any, position: any) => {
      const word = model.getWordAtPosition(position);
      if (!word) return null;

      const hoverDocs: Record<string, string> = {
        experiment: '**experiment(config?: ExperimentConfig): ExperimentBuilder**\n\nCreates a new ForgeScript experiment with fluent builder API.',
        timeline: '**timeline(name?: string): TimelineBuilder**\n\nCreates a new timeline within an experiment.',
        trial: '**trial(name?: string): TrialBuilder**\n\nCreates a new trial with stimuli and responses.',
        textStimulus: '**textStimulus(content: string, duration: number): Stimulus**\n\nCreates a text stimulus with specified content and duration in milliseconds.',
        imageStimulus: '**imageStimulus(url: string, duration: number): Stimulus**\n\nCreates an image stimulus from URL with specified duration.',
        keyboardResponse: '**keyboardResponse(validKeys?: string[], timeout?: number): Response**\n\nCreates a keyboard response collector with optional valid keys and timeout.'
      };

      const doc = hoverDocs[word.word];
      if (doc) {
        return {
          contents: [{ value: doc }]
        };
      }

      return null;
    }
  });
}

