     2→
     3→interface RenderNode {
     4→  id: string;
     5→  type: 'experiment' | 'timeline' | 'trial' | 'stimulus';
     6→  name: string;
     7→  x: number;
     8→  y: number;
     9→  width: number;
    10→  height: number;
    11→  startTime: number;
    12→  duration: number;
    13→  children?: RenderNode[];
    14→  data: any;
    15→}
    16→
    17→interface TimelineColors {
    18→  experiment: string;
    19→  timeline: string;
    20→  trial: string;
    21→  stimulus: string;
    22→  selected: string;
    23→  text: string;
    24→  grid: string;
    25→  ruler: string;
    26→}
    27→
    28→const DEFAULT_COLORS: TimelineColors = {
    29→  experiment: '#3b82f6',
    30→  timeline: '#8b5cf6',
    31→  trial: '#10b981',
    32→  stimulus: '#f59e0b',
    33→  selected: '#dc2626',
    34→  text: '#1f2937',
    35→  grid: '#e5e7eb',
    36→  ruler: '#6b7280'
    37→};
    38→
    39→export function createTimelineRenderer(ctx: CanvasRenderingContext2D) {
    40→  let experiment: CompiledExperiment | null = null;
    41→  let selectedElement: string | null = null;
    42→  let zoom = 1;
    43→  let panX = 0;
    44→  let panY = 0;
    45→  let width = 0;
    46→  let height = 0;
    47→  let renderTree: RenderNode | null = null;
    48→  
    49→  const pixelsPerMs = 0.1; // Base scale: 1 pixel = 10ms
    50→  const rowHeight = 60;
    51→  const rowGap = 10;
    52→  const nodeGap = 20;
    53→  const paddingX = 50;
    54→  const paddingY = 50;
    55→  
    56→  function setDimensions(w: number, h: number) {
    57→    width = w;
    58→    height = h;
    59→  }
    60→  
    61→  function setExperiment(exp: CompiledExperiment | null) {
    62→    experiment = exp;
    63→    if (exp) {
    64→      renderTree = buildRenderTree(exp);
    65→    } else {
    66→      renderTree = null;
    67→    }
    68→  }
    69→  
    70→  function setSelectedElement(id: string | null) {
    71→    selectedElement = id;
    72→  }
    73→  
    74→  function setZoom(z: number) {
    75→    zoom = z;
    76→  }
    77→  
    78→  function setPan(x: number, y: number) {
    79→    panX = x;
    80→    panY = y;
    81→  }
    82→  
    83→  function buildRenderTree(exp: CompiledExperiment): RenderNode {
    84→    const root: RenderNode = {
    85→      id: exp.id,
    86→      type: 'experiment',
    87→      name: exp.name,
    88→      x: 0,
    89→      y: 0,
    90→      width: 0,
    91→      height: 0,
    92→      startTime: 0,
    93→      duration: exp.duration || 0,
    94→      children: [],
    95→      data: exp
    96→    };
    97→    
    98→    let currentY = rowHeight + rowGap;
    99→    
   100→    // Build timeline nodes
   101→    exp.timelines?.forEach((timeline, tIndex) => {
   102→      const timelineNode: RenderNode = {
   103→        id: `timeline-${tIndex}`,
   104→        type: 'timeline',
   105→        name: timeline.name || `Timeline ${tIndex + 1}`,
   106→        x: 0,
   107→        y: currentY,
   108→        width: 0,
   109→        height: rowHeight,
   110→        startTime: timeline.startTime || 0,
   111→        duration: timeline.duration || 0,
   112→        children: [],
   113→        data: timeline
   114→      };
   115→      
   116→      currentY += rowHeight + rowGap;
   117→      
   118→      // Build trial nodes
   119→      timeline.trials?.forEach((trial, trIndex) => {
   120→        const trialNode: RenderNode = {
   121→          id: `trial-${tIndex}-${trIndex}`,
   122→          type: 'trial',
   123→          name: trial.name || `Trial ${trIndex + 1}`,
   124→          x: 0,
   125→          y: currentY,
   126→          width: 0,
   127→          height: rowHeight,
   128→          startTime: trial.startTime || 0,
   129→          duration: trial.duration || 0,
   130→          children: [],
   131→          data: trial
   132→        };
   133→        
   134→        currentY += rowHeight + rowGap;
