    32→    if (closeOnClickOutside && event.target === event.currentTarget) {
    33→      close();
    34→    }
    35→  }
    36→  
    37→  function close() {
    38→    open = false;
    39→    dispatch('close');
    40→  }
    41→  
    42→  function trapFocus(node: HTMLElement) {
    43→    const focusableElements = node.querySelectorAll(
    44→      'a[href], button, textarea, input[type="text"], input[type="radio"], input[type="checkbox"], select, [tabindex]:not([tabindex="-1"])'
    45→    );
    46→    
    47→    const firstFocusable = focusableElements[0] as HTMLElement;
    48→    const lastFocusable = focusableElements[focusableElements.length - 1] as HTMLElement;
    49→    
    50→    function handleTabKey(e: KeyboardEvent) {
    51→      if (e.key !== 'Tab') return;
    52→      
    53→      if (e.shiftKey) {
    54→        if (document.activeElement === firstFocusable) {
    55→          lastFocusable?.focus();
    56→          e.preventDefault();
    57→        }
    58→      } else {
    59→        if (document.activeElement === lastFocusable) {
    60→          firstFocusable?.focus();
    61→          e.preventDefault();
    62→        }
    63→      }
    64→    }
    65→    
    66→    node.addEventListener('keydown', handleTabKey);
    67→    firstFocusable?.focus();
    68→    
    69→    return {
    70→      destroy() {
    71→        node.removeEventListener('keydown', handleTabKey);
    72→      }
    73→    };
    74→  }
    75→  
    76→  $: if (open) {
    77→    previousFocus = document.activeElement as HTMLElement;
    78→  } else if (previousFocus) {
    79→    previousFocus.focus();
    80→    previousFocus = null;
    81→  }
    82→</script>
    83→
    84→{#if open}
    85→  <div
    86→    class="modal-backdrop"
    87→    on:click={handleClickOutside}
    88→    on:keydown={handleKeydown}
    89→    transition:fade={{ duration: 150 }}
    90→    role="presentation"
    91→  >
    92→    <div
    93→      bind:this={modal}
    94→      class="modal {sizeClasses[size]}"
    95→      role="dialog"
    96→      aria-modal="true"
    97→      aria-labelledby={title ? 'modal-title' : undefined}
    98→      transition:scale={{ duration: 150, start: 0.95 }}
    99→      use:trapFocus
   100→    >
   101→      {#if title || showCloseButton}
   102→        <div class="modal-header">
   103→          {#if title}
   104→            <h2 id="modal-title" class="modal-title">{title}</h2>
   105→          {/if}
   106→          {#if showCloseButton}
   107→            <button
   108→              type="button"
   109→              class="modal-close"
   110→              on:click={close}
   111→              aria-label="Close modal"
   112→            >
   113→              <X size={20} />
   114→            </button>
   115→          {/if}
   116→        </div>
   117→      {/if}
   118→      
   119→      <div class="modal-content">
   120→        <slot />
   121→      </div>
   122→      
   123→      {#if $$slots.footer}
