/* Root CSS Variables and Theme Definitions */

:root {
	/* Color Palette - Light Theme */
	--color-primary: #3b82f6;
	--color-primary-hover: #2563eb;
	--color-secondary: #8b5cf6;
	--color-secondary-hover: #7c3aed;
	--color-success: #10b981;
	--color-warning: #f59e0b;
	--color-error: #ef4444;
	--color-info: #3b82f6;

	/* Neutral Colors */
	--color-background: #ffffff;
	--color-surface: #f8fafc;
	--color-surface-hover: #f1f5f9;
	--color-border: #e2e8f0;
	--color-text: #1e293b;
	--color-text-secondary: #64748b;
	--color-text-disabled: #cbd5e1;

	/* Shadows */
	--shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.05);
	--shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);
	--shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1);

	/* Typography */
	--font-family: 'Inter var', system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
	--font-family-mono: 'JetBrains Mono', 'Fira Code', Consolas, 'Courier New', monospace;

	/* Font Sizes */
	--text-xs: 0.75rem;
	--text-sm: 0.875rem;
	--text-base: 1rem;
	--text-lg: 1.125rem;
	--text-xl: 1.25rem;
	--text-2xl: 1.5rem;
	--text-3xl: 1.875rem;

	/* Spacing */
	--space-1: 0.25rem;
	--space-2: 0.5rem;
	--space-3: 0.75rem;
	--space-4: 1rem;
	--space-5: 1.25rem;
	--space-6: 1.5rem;
	--space-8: 2rem;
	--space-10: 2.5rem;
	--space-12: 3rem;

	/* Border Radius */
	--radius-sm: 0.125rem;
	--radius-md: 0.375rem;
	--radius-lg: 0.5rem;
	--radius-full: 9999px;

	/* Transitions */
	--transition-fast: 150ms cubic-bezier(0.4, 0, 0.2, 1);
	--transition-base: 200ms cubic-bezier(0.4, 0, 0.2, 1);
	--transition-slow: 300ms cubic-bezier(0.4, 0, 0.2, 1);

	/* Z-index scale */
	--z-dropdown: 1000;
	--z-sticky: 1020;
	--z-fixed: 1030;
	--z-modal-backdrop: 1040;
	--z-modal: 1050;
	--z-popover: 1060;
	--z-tooltip: 1070;
}

/* Dark Theme */
:root.dark {
	--color-primary: #60a5fa;
	--color-primary-hover: #3b82f6;
	--color-secondary: #a78bfa;
	--color-secondary-hover: #8b5cf6;

	--color-background: #0f172a;
	--color-surface: #1e293b;
	--color-surface-hover: #334155;
	--color-border: #334155;
	--color-text: #f1f5f9;
	--color-text-secondary: #94a3b8;
	--color-text-disabled: #475569;

	--shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.3);
	--shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.4), 0 2px 4px -2px rgb(0 0 0 / 0.4);
	--shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.5), 0 4px 6px -4px rgb(0 0 0 / 0.5);
}

/* High Contrast Theme */
:root.high-contrast {
	--color-primary: #0066cc;
	--color-primary-hover: #0052a3;
	--color-secondary: #6600cc;
	--color-secondary-hover: #5200a3;

	--color-background: #ffffff;
	--color-surface: #f0f0f0;
	--color-surface-hover: #e0e0e0;
	--color-border: #000000;
	--color-text: #000000;
	--color-text-secondary: #333333;
	--color-text-disabled: #666666;

	--shadow-sm: 0 0 0 2px #000000;
	--shadow-md: 0 0 0 2px #000000;
	--shadow-lg: 0 0 0 2px #000000;
}

/* Font size adjustments */
:root[data-font-size="small"] {
	--text-xs: 0.625rem;
	--text-sm: 0.75rem;
	--text-base: 0.875rem;
	--text-lg: 1rem;
	--text-xl: 1.125rem;
	--text-2xl: 1.25rem;
	--text-3xl: 1.5rem;
}

:root[data-font-size="large"] {
	--text-xs: 0.875rem;
	--text-sm: 1rem;
	--text-base: 1.125rem;
	--text-lg: 1.25rem;
	--text-xl: 1.5rem;
	--text-2xl: 1.875rem;
	--text-3xl: 2.25rem;
}

/* Global Styles */
*, *::before, *::after {
	box-sizing: border-box;
}

html {
	height: 100%;
	-webkit-text-size-adjust: 100%;
}

body {
	margin: 0;
	padding: 0;
	min-height: 100%;
	font-family: var(--font-family);
	font-size: var(--text-base);
	line-height: 1.5;
	color: var(--color-text);
	background-color: var(--color-background);
	-webkit-font-smoothing: antialiased;
	-moz-osx-font-smoothing: grayscale;
}

/* Focus styles for accessibility */
:focus-visible {
	outline: 2px solid var(--color-primary);
	outline-offset: 2px;
}

/* Reduce motion for accessibility */
@media (prefers-reduced-motion: reduce) {
	*,
	*::before,
	*::after {
		animation-duration: 0.01ms !important;
		animation-iteration-count: 1 !important;
		transition-duration: 0.01ms !important;
		scroll-behavior: auto !important;
	}
}

/* Utility classes */
.sr-only {
	position: absolute;
	width: 1px;
	height: 1px;
	padding: 0;
	margin: -1px;
	overflow: hidden;
	clip: rect(0, 0, 0, 0);
	white-space: nowrap;
	border-width: 0;
}

/* Custom scrollbar */
::-webkit-scrollbar {
	width: 8px;
	height: 8px;
}

::-webkit-scrollbar-track {
	background: var(--color-surface);
}

::-webkit-scrollbar-thumb {
	background: var(--color-border);
	border-radius: var(--radius-full);
}

::-webkit-scrollbar-thumb:hover {
	background: var(--color-text-disabled);
}

