     1→<script lang="ts">
     2→  import { onMount, onDestroy } from 'svelte';
     3→  import { createTimelineRenderer } from './TimelineRenderer';
     4→  import type { CompiledExperiment, TimelineNode } from '@psyforge/api';
     5→  
     6→  export let experiment: CompiledExperiment | null = null;
     7→  export let selectedElement: string | null = null;
     8→  export let zoom = 1;
     9→  export let panX = 0;
    10→  export let panY = 0;
    11→  
    12→  let canvas: HTMLCanvasElement;
    13→  let container: HTMLDivElement;
    14→  let renderer: ReturnType<typeof createTimelineRenderer>;
    15→  let animationFrame: number;
    16→  
    17→  // Handle window resize
    18→  function handleResize() {
    19→    if (!canvas || !container) return;
    20→    
    21→    const rect = container.getBoundingClientRect();
    22→    canvas.width = rect.width * window.devicePixelRatio;
    23→    canvas.height = rect.height * window.devicePixelRatio;
    24→    canvas.style.width = `${rect.width}px`;
    25→    canvas.style.height = `${rect.height}px`;
    26→    
    27→    if (renderer) {
    28→      renderer.setDimensions(rect.width, rect.height);
    29→      renderer.render();
    30→    }
    31→  }
    32→  
    33→  // Handle canvas interactions
    34→  function handleCanvasClick(event: MouseEvent) {
    35→    if (!renderer) return;
    36→    
    37→    const rect = canvas.getBoundingClientRect();
    38→    const x = event.clientX - rect.left;
    39→    const y = event.clientY - rect.top;
    40→    
    41→    const element = renderer.hitTest(x, y);
    42→    if (element) {
    43→      selectedElement = element.id;
    44→    } else {
    45→      selectedElement = null;
    46→    }
    47→  }
    48→  
    49→  // Pan handling
    50→  let isPanning = false;
    51→  let lastMouseX = 0;
    52→  let lastMouseY = 0;
    53→  
    54→  function handleMouseDown(event: MouseEvent) {
    55→    if (event.button === 1 || (event.button === 0 && event.shiftKey)) {
    56→      isPanning = true;
    57→      lastMouseX = event.clientX;
    58→      lastMouseY = event.clientY;
    59→      canvas.style.cursor = 'grabbing';
    60→    }
    61→  }
    62→  
    63→  function handleMouseMove(event: MouseEvent) {
    64→    if (isPanning) {
    65→      const deltaX = event.clientX - lastMouseX;
    66→      const deltaY = event.clientY - lastMouseY;
    67→      panX += deltaX;
    68→      panY += deltaY;
    69→      lastMouseX = event.clientX;
    70→      lastMouseY = event.clientY;
    71→      
    72→      if (renderer) {
    73→        renderer.setPan(panX, panY);
    74→        renderer.render();
    75→      }
    76→    }
    77→  }
    78→  
    79→  function handleMouseUp() {
    80→    isPanning = false;
    81→    canvas.style.cursor = 'default';
    82→  }
    83→  
    84→  // Zoom handling
    85→  function handleWheel(event: WheelEvent) {
    86→    event.preventDefault();
    87→    
    88→    const delta = event.deltaY * -0.001;
    89→    const newZoom = Math.max(0.1, Math.min(5, zoom + delta));
    90→    
    91→    if (newZoom !== zoom) {
    92→      zoom = newZoom;
    93→      
    94→      if (renderer) {
    95→        renderer.setZoom(zoom);
    96→        renderer.render();
    97→      }
    98→    }
    99→  }
   100→  
   101→  // React to prop changes
   102→  $: if (renderer && experiment) {
   103→    renderer.setExperiment(experiment);
   104→    renderer.setSelectedElement(selectedElement);
   105→    renderer.render();
   106→  }
   107→  
