   114→  onMount(() => {
   115→    const ctx = canvas.getContext('2d');
   116→    if (!ctx) {
   117→      console.error('Failed to get 2D context');
   118→      return;
   119→    }
   120→    
   121→    renderer = createTimelineRenderer(ctx);
   122→    handleResize();
   123→    
   124→    // Set up resize observer
   125→    const resizeObserver = new ResizeObserver(handleResize);
   126→    resizeObserver.observe(container);
