   309→
   310→    this.isRunning = true;
   311→
   312→    try {
   313→      // Initialize timing and scheduling systems
   314→      const { PrecisionClock } = await import('@psyforge/timing');
   315→      const { createScheduler } = await import('@psyforge/scheduling');
   316→      
